const notes = [
  { id: 'N001', title: 'P2 — onboarding flow — July 10', content: 'User could not find the Add Task button. Spent 90 seconds looking in the sidebar. Eventually found it via the keyboard shortcut tooltip. Said: "Why is this not more obvious?"', source: 'Usability test', participant_code: 'P2' },
  { id: 'N002', title: 'NPS R012 — search critique', content: 'The search function is terrible. I cannot find tasks from 3 months ago without scrolling through everything.', source: 'NPS survey', participant_code: 'R012' },
  { id: 'N003', title: 'Interview T3 — switching motivation', content: 'We switched from Asana because the recurring tasks feature was the only thing we actually needed. Asana had it buried 4 clicks deep.', source: 'Customer interview', participant_code: 'T3' },
  { id: 'N004', title: 'NPS R005 — recurring tasks delight', content: 'Best project tool I have used in 10 years. The recurring tasks feature saved us probably 2 hours per week.', source: 'NPS survey', participant_code: 'R005' },
  { id: 'N005', title: 'Interview T7 — collaboration friction', content: 'About half my team still uses a spreadsheet. They resist the tool because the onboarding is too long and they don\'t see the value quickly enough.', source: 'Customer interview', participant_code: 'T7' }
];
return [{ json: { notes, taxonomy: { themes: ['onboarding', 'discoverability', 'recurring-tasks', 'team-adoption', 'search', 'mobile', 'integrations'], personas: ['casual-activator', 'team-lead', 'enterprise-pm'], evidence_types: ['usability-test', 'survey', 'interview', 'analytics'] } } }];

const { notes, taxonomy } = $input.first().json;
const system = `You are a UX research librarian. You tag research notes with structured metadata from a taxonomy. You assign themes, personas, sentiment, confidence level, and actionability. Return ONLY valid JSON.`;
const taxText = `Themes: ${taxonomy.themes.join(', ')}
Personas: ${taxonomy.personas.join(', ')}
Evidence types: ${taxonomy.evidence_types.join(', ')}`;
const notesText = notes.map(n => `  [${n.id}] Source: ${n.source}
  Title: ${n.title}
  Content: ${n.content}`).join('

');
const user = `Tag these research notes using this taxonomy:
${taxText}

Notes:
${notesText}

Return JSON:
{
  "tagged_notes": [
    {
      "id": "string",
      "themes": ["string — from taxonomy"],
      "personas": ["string — from taxonomy, or 'unknown'"],
      "sentiment": "positive|negative|neutral|mixed",
      "evidence_type": "string — from taxonomy",
      "confidence": "high|medium|low",
      "actionable": true,
      "insight_statement": "string — one-sentence insight derived from this note",
      "suggested_follow_up": "string — what additional research would validate this"|null
    }
  ]
}`;
return [{ json: { notes, taxonomy, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.tagged_notes || !Array.isArray(parsed.tagged_notes)) return [{ json: { _error: true, reason: 'Missing tagged_notes' } }];
return [{ json: { _error: false, result: parsed, meta: { note_count: parsed.tagged_notes.length, generated_at: new Date().toISOString() } } }];

const { result: r, meta: m } = $input.first().json;
const lines = (r.tagged_notes||[]).map(n =>
  `[${n.id}] ${n.sentiment?.toUpperCase()} | Evidence: ${n.evidence_type} | Confidence: ${n.confidence}${n.actionable?' [ACTIONABLE]':''}\n  Themes: ${(n.themes||[]).join(', ')}\n  Personas: ${(n.personas||[]).join(', ')}\n  Insight: ${n.insight_statement}${n.suggested_follow_up ? '\n  Follow-up: '+n.suggested_follow_up : ''}`
).join('\n\n');
const report = [
  `RESEARCH REPOSITORY TAGS`,
  `Tagged ${m.note_count} notes | Generated: ${m.generated_at}`,
  ``,
  lines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
